use core::str;
use std::sync::OnceLock;

use error_stack::{Report, ResultExt};
use validator::Validate;

use crate::error::TrustedServerError;
use crate::settings::{EdgeCookie, Publisher, Settings};

pub use crate::auction_config_types::AuctionConfig;

const SETTINGS_DATA: &[u8] = include_bytes!("../../../target/trusted-server-out.toml");
static SETTINGS: OnceLock<Settings> = OnceLock::new();

/// Creates a new [`Settings`] instance from the embedded configuration file.
///
/// Loads the pre-built TOML that was generated by `build.rs` (base config
/// merged with any `TRUSTED_SERVER__` environment variable overrides at
/// build time). Environment variables are **not** read at runtime.
///
/// # Errors
///
/// - [`TrustedServerError::InvalidUtf8`] if the embedded TOML file contains invalid UTF-8
/// - [`TrustedServerError::Configuration`] if the configuration is invalid or missing required fields
pub fn get_settings() -> Result<Settings, Report<TrustedServerError>> {
    if let Some(settings) = SETTINGS.get() {
        return Ok(settings.clone());
    }

    let settings = load_settings()?;
    if SETTINGS.set(settings.clone()).is_err() {
        if let Some(settings) = SETTINGS.get() {
            return Ok(settings.clone());
        }
    }

    Ok(settings)
}

fn load_settings() -> Result<Settings, Report<TrustedServerError>> {
    let toml_bytes = SETTINGS_DATA;
    let toml_str = str::from_utf8(toml_bytes).change_context(TrustedServerError::InvalidUtf8 {
        message: "embedded trusted-server.toml file".to_string(),
    })?;

    let settings = Settings::from_toml(toml_str)?;

    // Validate the settings
    settings
        .validate()
        .change_context(TrustedServerError::Configuration {
            message: "Failed to validate configuration".to_string(),
        })?;

    if !settings.proxy.certificate_check {
        log::warn!(
            "INSECURE: proxy.certificate_check is disabled — TLS certificates will NOT be verified"
        );
    }

    if EdgeCookie::is_placeholder_secret_key(settings.edge_cookie.secret_key.expose()) {
        log::warn!(
            "INSECURE: edge_cookie.secret_key is set to a default placeholder — \
             HMAC-SHA256 signatures can be forged. \
             Override via TRUSTED_SERVER__EDGE_COOKIE__SECRET_KEY at build time"
        );
    }

    if Publisher::is_placeholder_proxy_secret(settings.publisher.proxy_secret.expose()) {
        log::warn!(
            "INSECURE: publisher.proxy_secret is set to a default placeholder — \
             XChaCha20-Poly1305 encrypted URLs can be decrypted by anyone. \
             Override via TRUSTED_SERVER__PUBLISHER__PROXY_SECRET at build time"
        );
    }

    Ok(settings)
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn get_settings_loads_embedded_toml_successfully() {
        // The embedded TOML contains placeholder secrets (e.g. "trusted-server",
        // "change-me-proxy-secret"). This is expected — production builds override
        // them via TRUSTED_SERVER__* env vars at build time.
        let settings = get_settings().expect("should load settings from embedded TOML");
        assert!(!settings.publisher.domain.is_empty());
        assert!(!settings.publisher.cookie_domain.is_empty());
        assert!(!settings.publisher.origin_url.is_empty());
    }
}
